INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '16fd6186-341b-4e1b-854a-e216a460884e',
  '00000000-0000-0000-0000-000000000001',
  $escape$tcp_ip: Navigating the OSI Model for Debugging$escape$,
  $escape$When troubleshooting TCP/IP connections, understanding the OSI model's layers is crucial. The model divides the communication process into seven layers: Physical, Data Link, Network, Transport, Session, Presentation, and Application.

At the TCP/IP layer, the Transport layer (Layer 4) handles segmentation and reassembly of data, while the Internet layer (Layer 3) routes packets between networks. The Application layer (Layer 7) defines the format of the data, while the Socket API interacts with the Transport layer. To debug TCP/IP issues, start by identifying the affected layer and use the relevant tools and APIs, such as `netstat` for network statistics and `tcpdump` for packet capture.$escape$,
  NULL,
  NULL,
