INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'aa34f948-6490-42f2-ad45-ef6749a91545',
  '00000000-0000-0000-0000-000000000001',
  $escape$tcp_ip: Optimizing DNS Resolution Chains with TTL and Record Types$escape$,
  $escape$When using tcp_ip to resolve DNS queries, it's essential to understand the resolution chain, TTL (Time-To-Live), and record types. The resolution chain consists of a series of recursive DNS lookups, typically starting from a root DNS server. The TTL specifies the maximum time a DNS record is considered valid. tcp_ip supports various record types, such as A, AAAA, MX, and TXT. To optimize resolution chains, consider using DNS over HTTPS (DoH) for increased security and privacy. Additionally, split horizon DNS allows for different DNS responses based on the client's IP address, enabling more efficient and secure DNS resolution.$escape$,
  NULL,
  NULL,
