INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '54b6d392-dd37-4e72-87ee-e28b4c0b7e0b',
  '00000000-0000-0000-0000-000000000001',
  $escape$tcp_ip: Understanding QUIC's Connection Migration$escape$,
  $escape$When migrating a QUIC connection, the sender retransmits unacknowledged packets. To avoid duplicate packets, the receiver sends a MaxAckDelay hint indicating the maximum time before acknowledging a packet. This allows the sender to optimize retransmissions. The sender uses the hint to determine the optimal retransmission interval. For example, if the hint is set to 10ms, the sender will retransmit packets with a delay of 10ms.$escape$,
  NULL,
  NULL,
