INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c49ecf45-2d67-47fb-9a5b-063e7c171c33',
  '00000000-0000-0000-0000-000000000001',
  $escape$tcp_ip Congestion Control — CUBIC vs BBR vs QUIC$escape$,
  $escape$CUBIC, BBR, and QUIC employ distinct congestion control strategies on tcp_ip. CUBIC (CUBIC, 2007) adapts to network dynamics using a cubic growth function. BBR (Google's BBR, 2016) measures buffer occupancy to adjust sending rates. QUIC (IETF's QUIC, 2019) uses a separate congestion control protocol (CC). CUBIC and BBR operate within the standard tcp_ip congestion avoidance algorithm's framework, adjusting the congestion window (cwnd). In contrast, QUIC's CC is designed for low-latency, high-bandwidth networks, making it more suitable for real-time applications.$escape$,
  NULL,
  NULL,
