INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ec05a5ae-c605-491f-ac8a-56247e5844be',
  '00000000-0000-0000-0000-000000000001',
  $escape$tcp_ip - Zero-Copy Networking with sendfile and splice$escape$,
  $escape$tcp_ip's sendfile and splice APIs enable zero-copy networking, reducing CPU overhead by bypassing user space. sendfile transfers data directly from the file system cache to the socket buffer, while splice moves data from a file descriptor to a socket or pipe. By leveraging DMA (Direct Memory Access) and CPU-efficient I/O paths, these APIs conserve system resources and improve performance.$escape$,
  NULL,
  NULL,
